console.log(10 + 5);     // 15
console.log(10 - 5);     // 5
console.log(10 * 5);     // 50
console.log(10 / 5);     // 2
console.log(10 % 3);     // 1 (remainder)
console.log(2 ** 3);     // 8 (2 to the power of 3)

// With variables
let x = 20;
let y = 3;
console.log(x + y);      // 23

// AND
console.log(true && true);    // true
console.log(true && false);   // false
console.log(false && false);  // false

// OR
console.log(true || false);   // true
console.log(false || false);  // false

// NOT
console.log(!true);           // false
console.log(!false);          // true

// Real example
let age = 18;
let hasLicense = true;
console.log(age >= 18 && hasLicense); // true (old enough AND has license)
